import {
  WebSocketGateway,
  WebSocketServer,
  OnGatewayConnection,
  OnGatewayDisconnect,
} from '@nestjs/websockets';
import { Logger } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import type { Namespace, Socket } from 'socket.io';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { getPriceStoreKeys } from '../prices/price-key-mapping';

/** Состояние одной комнаты */
interface RoomState {
  intervalId: ReturnType<typeof setInterval>;
  bid: number;
  ask: number;
  bidKey: string;
  askKey: string;
}

/**
 * Socket.IO Gateway для live-chart.
 *
 * Клиент подключается к namespace /live-chart, передавая:
 *   - handshake.auth.token  — JWT access-токен
 *   - handshake.query.subscriptionId — UUID подписки
 *
 * Сервер помещает клиента в room "subscription:<id>" и
 * периодически генерирует случайные ценовые обновления
 * с реальными ключами из price-key-mapping (sourceId + pairId).
 */
@WebSocketGateway({
  namespace: '/live-chart',
  cors: {
    origin: '*',
    credentials: false,
  },
})
export class LiveChartGateway
  implements OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server: Namespace;

  private readonly logger = new Logger(LiveChartGateway.name);

  /** roomId → состояние генерации */
  private readonly rooms = new Map<string, RoomState>();

  /** socketId → roomId */
  private readonly socketRooms = new Map<string, string>();

  constructor(
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {}

  /** Вызывается при подключении клиента */
  async handleConnection(client: Socket): Promise<void> {
    // 1. Верификация JWT
    const token = client.handshake.auth?.token as string | undefined;
    if (token) {
      try {
        this.jwtService.verify(token, {
          secret: this.configService.get<string>('jwt.accessSecret'),
        });
      } catch {
        this.logger.warn(`Клиент ${client.id}: неверный JWT, отключаем`);
        client.disconnect();
        return;
      }
    }

    // 2. Получаем subscriptionId из query-параметров
    const subscriptionId = client.handshake.query?.subscriptionId as
      | string
      | undefined;
    if (!subscriptionId) {
      this.logger.warn(
        `Клиент ${client.id}: subscriptionId не передан, отключаем`,
      );
      client.disconnect();
      return;
    }

    const roomId = `subscription:${subscriptionId}`;

    // 3. Добавляем клиента в room
    void client.join(roomId);
    this.socketRooms.set(client.id, roomId);
    this.logger.log(`Клиент ${client.id} вошёл в комнату ${roomId}`);

    // 4. Если интервал для room ещё не запущен — запускаем
    if (!this.rooms.has(roomId)) {
      await this.startRoom(roomId, subscriptionId);
    }
  }

  /** Вызывается при отключении клиента */
  handleDisconnect(client: Socket): void {
    const roomId = this.socketRooms.get(client.id);
    if (!roomId) return;

    this.socketRooms.delete(client.id);
    this.logger.log(`Клиент ${client.id} покинул комнату ${roomId}`);

    // Проверяем, остались ли ещё клиенты в комнате
    const room = this.server.adapter.rooms?.get(roomId);
    if (!room || room.size === 0) {
      this.stopRoom(roomId);
    }
  }

  /**
   * Инициализирует генерацию данных для комнаты.
   * Определяет реальные ключи PriceStore по подписке из БД.
   */
  private async startRoom(
    roomId: string,
    subscriptionId: string,
  ): Promise<void> {
    // Получаем подписку из БД для определения реальных ключей
    const sub = await this.subsRepo.findOne({
      where: { id: subscriptionId },
    });

    let bidKey = 'live:chart|WETH/USDC|bidPrice';
    let askKey = 'live:chart|WETH/USDC|askPrice';

    if (sub) {
      const keys = getPriceStoreKeys(sub.sourceId, sub.pairId);
      if (keys) {
        bidKey = keys.bidKey;
        askKey = keys.askKey;
        this.logger.log(
          `Комната ${roomId}: маппинг найден → bid=${bidKey}, ask=${askKey}`,
        );
      } else {
        this.logger.warn(
          `Комната ${roomId}: маппинг не найден для sourceId="${sub.sourceId}", pairId="${sub.pairId}", используем fallback`,
        );
      }
    } else {
      this.logger.warn(
        `Комната ${roomId}: подписка не найдена, используем fallback-ключи`,
      );
    }

    const basePrice = 2000 + Math.random() * 300;
    const state: RoomState = {
      intervalId: null as any,
      bid: basePrice,
      ask: basePrice + 0.5 + Math.random() * 2,
      bidKey,
      askKey,
    };

    state.intervalId = setInterval(() => {
      this.emitPriceUpdate(roomId);
    }, 2000);

    this.rooms.set(roomId, state);
    this.logger.log(`Запущен интервал для комнаты ${roomId}`);
  }

  /** Останавливает генерацию данных для комнаты */
  private stopRoom(roomId: string): void {
    const state = this.rooms.get(roomId);
    if (state) {
      clearInterval(state.intervalId);
      this.rooms.delete(roomId);
      this.logger.log(
        `Интервал для комнаты ${roomId} остановлен (нет клиентов)`,
      );
    }
  }

  /**
   * Генерирует случайные bid/ask и рассылает их в room.
   * Формат сообщения: { key: string, point: { t: number, v: number } }
   */
  private emitPriceUpdate(roomId: string): void {
    const state = this.rooms.get(roomId);
    if (!state) return;

    // Случайный дрейф цены
    state.bid += (Math.random() - 0.5) * 10;
    state.bid = Math.max(1500, Math.min(2800, state.bid));
    state.ask = state.bid + 0.5 + Math.random() * 2;

    const t = Date.now();

    // Отправляем bid
    this.server.to(roomId).emit('priceUpdate', {
      key: state.bidKey,
      point: { t, v: parseFloat(state.bid.toFixed(3)) },
    });

    // Отправляем ask
    this.server.to(roomId).emit('priceUpdate', {
      key: state.askKey,
      point: { t, v: parseFloat(state.ask.toFixed(3)) },
    });
  }
}

import {
  WebSocketGateway,
  WebSocketServer,
  OnGatewayConnection,
  OnGatewayDisconnect,
} from '@nestjs/websockets';
import { Logger } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import type { Namespace, Socket } from 'socket.io';
import { io as ioClient, Socket as ClientSocket } from 'socket.io-client';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { getPriceStoreKeys } from '../prices/price-key-mapping';

/** Сообщение dataChange от arbiDexMarketData */
interface DataChangeMessage {
  key: string;
  point: { t: number; v: number };
}

/** Состояние одной комнаты — подключение к arbiDexMarketData */
interface RoomState {
  /** Socket.IO клиент к arbiDexMarketData /store namespace */
  upstreamSocket: ClientSocket;
  /** Ключи, на которые подписана комната */
  bidKey: string;
  askKey: string;
}

/**
 * Socket.IO Gateway для live-chart.
 *
 * Клиент подключается к namespace /live-chart, передавая:
 *   - handshake.auth.token  — JWT access-токен
 *   - handshake.query.subscriptionId — UUID подписки
 *
 * Сервер помещает клиента в room "subscription:<id>" и
 * подключается к arbiDexMarketData /store для получения
 * реальных ценовых обновлений, которые ретранслирует клиентам.
 */
@WebSocketGateway({
  namespace: '/live-chart',
  cors: {
    origin: '*',
    credentials: false,
  },
})
export class LiveChartGateway
  implements OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server: Namespace;

  private readonly logger = new Logger(LiveChartGateway.name);

  /** URL сервиса arbiDexMarketData */
  private readonly marketDataUrl: string;

  /** roomId → состояние подключения к upstream */
  private readonly rooms = new Map<string, RoomState>();

  /** socketId → roomId */
  private readonly socketRooms = new Map<string, string>();

  constructor(
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl =
      this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /** Вызывается при подключении клиента */
  async handleConnection(client: Socket): Promise<void> {
    // 1. Верификация JWT
    const token = client.handshake.auth?.token as string | undefined;
    if (token) {
      try {
        this.jwtService.verify(token, {
          secret: this.configService.get<string>('jwt.accessSecret'),
        });
      } catch {
        this.logger.warn(`Клиент ${client.id}: неверный JWT, отключаем`);
        client.disconnect();
        return;
      }
    }

    // 2. Получаем subscriptionId из query-параметров
    const subscriptionId = client.handshake.query?.subscriptionId as
      | string
      | undefined;
    if (!subscriptionId) {
      this.logger.warn(
        `Клиент ${client.id}: subscriptionId не передан, отключаем`,
      );
      client.disconnect();
      return;
    }

    const roomId = `subscription:${subscriptionId}`;

    // 3. Добавляем клиента в room
    void client.join(roomId);
    this.socketRooms.set(client.id, roomId);
    this.logger.log(`Клиент ${client.id} вошёл в комнату ${roomId}`);

    // 4. Если upstream-подключение для room ещё не создано — создаём
    if (!this.rooms.has(roomId)) {
      await this.startRoom(roomId, subscriptionId);
    }
  }

  /** Вызывается при отключении клиента */
  handleDisconnect(client: Socket): void {
    const roomId = this.socketRooms.get(client.id);
    if (!roomId) return;

    this.socketRooms.delete(client.id);
    this.logger.log(`Клиент ${client.id} покинул комнату ${roomId}`);

    // Проверяем, остались ли ещё клиенты в комнате
    const room = this.server.adapter.rooms?.get(roomId);
    if (!room || room.size === 0) {
      this.stopRoom(roomId);
    }
  }

  /**
   * Подключается к arbiDexMarketData Socket.IO /store namespace
   * и подписывается на ключи bid/ask для данной подписки.
   */
  private async startRoom(
    roomId: string,
    subscriptionId: string,
  ): Promise<void> {
    // Получаем подписку из БД для определения реальных ключей
    const sub = await this.subsRepo.findOne({
      where: { id: subscriptionId },
    });

    let bidKey = 'dex:arbitrum|WETH/USDC|bidPrice';
    let askKey = 'dex:arbitrum|WETH/USDC|askPrice';

    if (sub) {
      const keys = getPriceStoreKeys(sub.sourceId, sub.pairId);
      if (keys) {
        bidKey = keys.bidKey;
        askKey = keys.askKey;
        this.logger.log(
          `Комната ${roomId}: маппинг найден → bid=${bidKey}, ask=${askKey}`,
        );
      } else {
        this.logger.warn(
          `Комната ${roomId}: маппинг не найден для sourceId="${sub.sourceId}", pairId="${sub.pairId}", используем fallback`,
        );
      }
    } else {
      this.logger.warn(
        `Комната ${roomId}: подписка не найдена, используем fallback-ключи`,
      );
    }

    // Подключаемся к arbiDexMarketData Socket.IO /store namespace
    const upstreamSocket = ioClient(`${this.marketDataUrl}/store`, {
      transports: ['websocket'],
      reconnection: true,
      reconnectionAttempts: 10,
      reconnectionDelay: 2000,
    });

    upstreamSocket.on('connect', () => {
      this.logger.log(
        `Комната ${roomId}: подключено к arbiDexMarketData /store (${upstreamSocket.id})`,
      );

      // Подписываемся на нужные ключи
      upstreamSocket.emit('subscribe', { keys: [bidKey, askKey] });
    });

    upstreamSocket.on('subscribed', (info: { keys: string[] | 'all' }) => {
      this.logger.log(
        `Комната ${roomId}: подписка на ключи подтверждена: ${JSON.stringify(info.keys)}`,
      );
    });

    // Ретрансляция dataChange → priceUpdate
    upstreamSocket.on('dataChange', (msg: DataChangeMessage) => {
      this.server.to(roomId).emit('priceUpdate', {
        key: msg.key,
        point: msg.point,
      });
    });

    upstreamSocket.on('connect_error', (err: Error) => {
      this.logger.error(
        `Комната ${roomId}: ошибка подключения к arbiDexMarketData — ${err.message}`,
      );
    });

    upstreamSocket.on('disconnect', (reason: string) => {
      this.logger.warn(
        `Комната ${roomId}: upstream отключён — ${reason}`,
      );
    });

    const state: RoomState = {
      upstreamSocket,
      bidKey,
      askKey,
    };

    this.rooms.set(roomId, state);
    this.logger.log(`Запущен upstream для комнаты ${roomId}`);
  }

  /** Останавливает upstream-подключение для комнаты */
  private stopRoom(roomId: string): void {
    const state = this.rooms.get(roomId);
    if (state) {
      // Отписываемся и отключаемся от arbiDexMarketData
      state.upstreamSocket.emit('unsubscribe');
      state.upstreamSocket.disconnect();
      this.rooms.delete(roomId);
      this.logger.log(
        `Upstream для комнаты ${roomId} остановлен (нет клиентов)`,
      );
    }
  }
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { getPriceStoreKeys } from './price-key-mapping';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly botsUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.botsUrl = this.configService.get<string>('bots.url') ?? 'http://localhost:3000';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   */
  async getPricesBySubscription(subscriptionId: string, userId: string): Promise<SubscriptionPriceData> {
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Маппинг в ключи PriceStore
    const keys = getPriceStoreKeys(sub.sourceId, sub.pairId);
    if (!keys) {
      throw new BadRequestException(
        `Маппинг не найден для sourceId="${sub.sourceId}", pairId="${sub.pairId}". ` +
        `Проверьте конфигурацию price-key-mapping.ts`,
      );
    }

    // 3. Запрос к arbiDexServerBots
    const { bidKey, askKey, mapping } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.botsUrl}/prices/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexServerBots: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервера котировок (${this.botsUrl}). ` +
        `Убедитесь что arbiDexServerBots запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
      if (point.askPrice === 0 && lastAsk !== 0) point.askPrice = lastAsk;
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий
    const sourceName = mapping.sourcePrefix;
    const series: PriceSeriesConfig[] = [
      { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
      { key: 'askPrice', name: `${sourceName} Ask`, color: '#f6465d' },
    ];

    return { series, data: sorted };
  }
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { getPriceStoreKeys } from './price-key-mapping';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly marketDataUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl = this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   */
  async getPricesBySubscription(subscriptionId: string, userId: string): Promise<SubscriptionPriceData> {
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Маппинг в ключи PriceStore
    const keys = getPriceStoreKeys(sub.sourceId, sub.pairId);
    if (!keys) {
      throw new BadRequestException(
        `Маппинг не найден для sourceId="${sub.sourceId}", pairId="${sub.pairId}". ` +
        `Проверьте конфигурацию price-key-mapping.ts`,
      );
    }

    // 3. Запрос к arbiDexServerBots
    const { bidKey, askKey, mapping } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.marketDataUrl}/store/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexMarketData: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервиса котировок (${this.marketDataUrl}). ` +
        `Убедитесь что arbiDexMarketData запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
      if (point.askPrice === 0 && lastAsk !== 0) point.askPrice = lastAsk;
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий
    const sourceName = mapping.sourcePrefix;
    const series: PriceSeriesConfig[] = [
      { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
      { key: 'askPrice', name: `${sourceName} Ask`, color: '#f6465d' },
    ];

    return { series, data: sorted };
  }
}

import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { io, Socket } from 'socket.io-client';

/** Формат одного сообщения от live-chart gateway */
export interface LiveChartMessage {
  /** Ключ серии, например: "live:chart|WETH/USDC|bidPrice" */
  key: string;
  /** Ценовая точка: timestamp + значение */
  point: { t: number; v: number };
}

/**
 * Сервис для работы с Socket.IO live-chart namespace.
 * Подключается к /live-chart на сервере, передаёт JWT и subscriptionId,
 * получает live-обновления цен.
 */
@Injectable({ providedIn: 'root' })
export class LiveChartSocketService {
  private socket: Socket | null = null;

  /** Базовый URL WebSocket-сервера (без /api prefix) */
  private readonly wsUrl = 'http://localhost:3002';

  /**
   * Подключиться к Gateway и вернуть Observable с входящими сообщениями.
   * При ансабскрайбе от Observable соединение НЕ закрывается автоматически —
   * для закрытия нужно вызвать disconnect() явно (в ngOnDestroy).
   *
   * @param token    JWT access token
   * @param subscriptionId  UUID подписки
   */
  connect(token: string, subscriptionId: string): Observable<LiveChartMessage> {
    this.disconnect();

    this.socket = io(`${this.wsUrl}/live-chart`, {
      auth: { token },
      query: { subscriptionId },
      transports: ['websocket'],
    });

    return new Observable<LiveChartMessage>((observer) => {
      const socket = this.socket!;

      const onPriceUpdate = (msg: LiveChartMessage) => observer.next(msg);
      const onConnectError = (err: Error) => observer.error(err);

      socket.on('priceUpdate', onPriceUpdate);
      socket.on('connect_error', onConnectError);

      // Teardown: снимаем слушатели при ансабскрайбе
      return () => {
        socket.off('priceUpdate', onPriceUpdate);
        socket.off('connect_error', onConnectError);
      };
    });
  }

  /** Отключиться от Socket.IO и освободить ресурсы */
  disconnect(): void {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
    }
  }
}

